import tree_common;
import ussfo.sf_tree_info;
import usnyc.nyc_tree_info;
import usbos.boston_tree_info;
import frpar.paris_tree_info;
import usbtv.burlington_tree_info;

auto latest_update_through <- greatest(ussfo_data_updated_through, usnyc_data_updated_through, usbos_data_updated_through, frpar_data_updated_through, usbtv_data_updated_through);
# --- Merged union datasource ---

datasource tree_info (
    tree_id,
    city,
    species,
    tree_name,
    ?plant_date,
    ?diameter_at_breast_height,
    ?latitude,
    ?longitude,
    latest_update_through
)
grain (tree_id)
file f`https://storage.googleapis.com/trilogy_public_models/duckdb/trees/full_tree_info_v{data_version}.parquet`:f`gcs://trilogy_public_models/duckdb/trees/full_tree_info_v{data_version}.parquet`
freshness by latest_update_through;

key ecoregion_id int;

property ecoregion_id.ecoregion_name string; # e.g. California coastal sage and chaparral
property ecoregion_id.realm string; # nearctic | palearctic | neotropical | afrotropical | indo_malay | australasia | oceania | antarctic
property ecoregion_id.biome string; # canonical biome name
property ecoregion_id.biome_code int;
property ecoregion_id.realm_code string;

property ecoregion_id.country_codes list<string>;
property ecoregion_id.centroid_lat float;
property ecoregion_id.centroid_lon float;

property ecoregion_id.geometry_geojson string;
property ecoregion_id.bbox_min_lat float;
property ecoregion_id.bbox_min_lon float;
property ecoregion_id.bbox_max_lat float;
property ecoregion_id.bbox_max_lon float;

property ecoregion_id.is_terrestrial bool;
property ecoregion_id.source_version string;
property ecoregion_id.enriched_at datetime;

property <*>.ecoregion_data_updated_through datetime;

import std.geography;
import core;

# --- Shared landmark identity ---

key landmark_id string; # city-prefixed unique identifier (sf-<objectid>, nyc-<lm_id>)

property landmark_id.name string; # landmark name

# --- Geometry (computed from raw WKT) ---

property landmark_id.geometry_raw string; # raw WKT polygon/multipolygon

auto geometry <- geo_from_text(geometry_raw);
auto geo_centroid <- geo_centroid(geometry);
auto longitude <- geo_x(geo_centroid);
auto latitude <- geo_y(geo_centroid);

# --- SF-specific properties ---

property landmark_id.landmark_number int;   # official SF landmark number
property landmark_id.address string;        # street address
property landmark_id.property_type string;  # property type classification
property landmark_id.year_built int;        # year the structure was built
property landmark_id.year_designated int;   # year designated as landmark
property landmark_id.designation_age int;   # age at time of designation
property landmark_id.criteria_1 string;     # designation criteria 1 code
property landmark_id.criteria_2 string;     # designation criteria 2 code
property landmark_id.criteria_3 string;     # designation criteria 3 code
property landmark_id.criteria_1_text string;
property landmark_id.criteria_2_text string;
property landmark_id.criteria_3_text string;

# --- NYC-specific properties ---

property landmark_id.borough string;         # NYC borough
property landmark_id.lm_type string;         # landmark type (e.g. Scenic Landmark)
property landmark_id.designation_date date;  # official designation date

# --- Boston-specific properties ---

property landmark_id.neighborhood string;    # Boston neighborhood

# --- Paris-specific properties ---

property landmark_id.arrondissement string;   # Paris arrondissement (e.g. "Paris 1er Arrondissement")
property landmark_id.protection_type string;  # e.g. "1925/02/12 : inscrit MH" or "1862 : classé MH"
property landmark_id.denomination string;     # building type (e.g. "immeuble", "château", "église")

# --- Freshness tracking ---

property <*>.ussfo_landmark_data_updated_through datetime;
property <*>.usnyc_landmark_data_updated_through datetime;
property <*>.usbos_landmark_data_updated_through datetime;
property <*>.frpar_landmark_data_updated_through datetime;
property <*>.usbtv_landmark_data_updated_through datetime;
auto latest_landmark_update_through <- greatest(ussfo_landmark_data_updated_through, usnyc_landmark_data_updated_through, usbos_landmark_data_updated_through, frpar_landmark_data_updated_through, usbtv_landmark_data_updated_through);

import landmark_common;
import ussfo.sf_landmarks;
import usnyc.nyc_landmarks;
import usbos.boston_landmarks;
import frpar.paris_landmarks;
import usbtv.burlington_landmarks;


# --- Merged union datasource ---

datasource landmark_info (
    landmark_id,
    city,
    name,
    ?geometry,
    ?latitude,
    ?longitude,
    latest_landmark_update_through
)
grain (landmark_id)
file f`https://storage.googleapis.com/trilogy_public_models/duckdb/landmarks/full_landmark_info_v{data_version}.parquet`:f`gcs://trilogy_public_models/duckdb/landmarks/full_landmark_info_v{data_version}.parquet`
freshness by latest_landmark_update_through;

import tree_enrichment;
import ecoregion_info;
import std.display;

constant active_city <- 'USBTV';
constant active_city_ecoregion <- 334;
constant active_city_usda_zone <- 5;
constant active_city_biome <- 'Temperate Broadleaf & Mixed Forests';
constant active_city_realm <- 'nearctic';

def is_full_sun(x) -> x = 'full_sun';
def is_partial_shade(x) -> x = 'partial_shade';
def is_shade(x) -> x = 'shade';


property native_locality_bucket <- CASE
    WHEN ecoregion_id=active_city_ecoregion THEN 'Native'
    WHEN biome = active_city_biome THEN 'Same biome, non-native'
    WHEN realm = active_city_realm THEN 'Native Region, Different Biome'
  else 'Non-Native, Different Biome'
end::string;

auto hardiness_fit_bucket <- CASE
  when usda_zone_min is null or usda_zone_max is null then 'Unknown'
  when active_city_usda_zone < usda_zone_min or active_city_usda_zone > usda_zone_max then 'Outside zone'
  when active_city_usda_zone = usda_zone_min or active_city_usda_zone = usda_zone_max then 'Edge of tolerance'
  else 'Well within zone'
end::string;

auto water_resilience_bucket <- CASE
  when water_needs = 'high' and drought_tolerance = 'low' then 'High water / low drought tolerance'
  when water_needs = 'low' and drought_tolerance = 'high' then 'Low water / high drought tolerance'
  when water_needs is null or drought_tolerance is null then 'Unknown'
  else 'Moderate / mixed'
end::string;

auto lifespan_bucket <- CASE
  when lifespan_max_years is null and lifespan_min_years is null then 'Unknown'
  when coalesce(lifespan_max_years, lifespan_min_years) < 50 then 'Short-lived (<50y)'
  when coalesce(lifespan_max_years, lifespan_min_years) < 150 then 'Medium-lived (50-149y)'
  else 'Long-lived (150+y)'
end::string;

auto sun_exposure_label <- CASE
  when len(array_filter(sun_exposure, @is_shade)) > 0 then 'Shade'
  when len(array_filter(sun_exposure, @is_partial_shade)) > 0 then 'Partial shade'
  when len(array_filter(sun_exposure, @is_full_sun)) > 0 then 'Full sun'
end::string;

auto dominance_rank <- rank(species) over (order by count(tree_id) by species desc, species asc);

auto cumulative_tree_share_pct <- ((sum count(tree_id) by species order by dominance_rank asc) / (count(tree_id) by *))::float::percent;
